INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000001', '睡眠区', '舒曼波', '舒曼波的频段与人大脑的alpha波频率相似，这种波段可以促进放松和减少焦虑感，有助于促进睡眠', 'Hi，你好~欢迎来到耳界沉浸式疗愈空间~在这里，您可以放下生活的忙碌，进入一个宁静放松的世界，此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐，深吸一口气，还可以闻到沁人心脾的香气。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n现在，你正在体验到的是零重力模式，你可以把身体调整到最舒适的状态，轻轻闭上眼睛，跟随着声波的震动，享受身体的共振。在接下来的30分钟里，您将在智能疗愈系统的帮助下，进行“舒曼波”的体验。\n请保持呼吸的顺畅和身体的放松，你会听到和感受到低频的震动是舒曼波，这是一种自然界的频率，也被称为地球脑电波。舒曼波的频率与人大脑的alpha波频率相似，这种波段可以促进放松和减少焦虑感，有助于促进睡眠。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受平静、治愈的美好体验。\n想象一下，你的身体就像是一个乐器，正在随着舒曼波的旋律轻轻摇摆，轻轻，摇摆……\n\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n接下来，你身下的床将慢慢推你起身，\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。\n在这个沉浸式疗愈空间中，耳界智能疗愈系统调动了你全身的“力感受器”感知神经，他们都在感受舒曼波的振动和压力变化，舒曼波在你的体内产生微妙的作用，让你的身体变得更加轻盈，思维变得更加清晰。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n耳界earmersion，祝你拥有美好的一天，我们下次再会。', 50, '平静', '深度镇静', true, false, '18岁以上', '创伤后应激障碍，严重抑郁患者', '["创伤后应激障碍","严重抑郁患者","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000002', '睡眠区', '海洋冥想（同特禀质）', '自然情境深度减压，全身体感“放松海浪”，重点部位牵引', 'Hi，你好~欢迎来到耳界沉浸式疗愈空间~在这里，您可以放下生活的忙碌，进入一个宁静放松的世界，此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐，深吸一口气，还可以闻到沁人心脾的香气。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n现在，你正在体验到的是零重力模式，你可以把身体调整到最舒适的状态，轻轻闭上眼睛，并在此安放你的内心。在接下来的30分钟里，您将在智能疗愈系统的帮助下，进行“海洋冥想”的体验，联想大海的自由和广阔。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受平静、治愈的美好体验。\n\n想象着阳光，沙滩以及深邃无边的海洋……\n你正舒适的躺在海边的沙滩上，身旁是细细的、温暖的砂砾。浪花轻轻拍打着沙滩，卷起层层洁白的泡沫。\n微风轻轻地拂过你的脸庞，海浪涌上岸边，沾湿了你的脚背。\n一阵柔和的海风吹拂过来，你深深地吸了一口带着海洋气息的空气，又缓缓地呼气，伴随着气息的流通，内心囤积的压力逐渐被释放，你的身体也随着床体，慢慢放平，变得越来越轻，越来越轻。\n\n在接下来的时间里，将会进行一次身体扫描，这将会让你保持临在，感受全身的放松。在扫描的过程中，确保自己持续的保持知觉，了解当下发生的一切。更好的感受按摩对你的作用，了解在任何一个时刻里，自己觉察到了什么？体验到了什么？\n\n现在，从大脑开始，想象着一束温暖的光投射到你的头部，轻柔的探索，意识在大脑里流转，让大脑安静下来，放下各种念头，专注于现在的感受。\n\n光束继续下移，来到你的双肩，你会感受到肩胛部位受到智能气囊的推压作用。再一次，保持好奇心。现在这个部位有什么感受？你有没有任何收紧、舒展或其他感受？是否感受到在轻柔的气囊作用下，肩背部的僵硬、紧张得到了缓解。这种感觉延伸到你的脊柱，延伸到整个后背。仔细的感受被关照的感觉。\n放松你的身体，不要着急，多花几分钟，慢慢感受。\n吸气，\n呼气。\n\n\n现在，光束聚焦到你的腰部和双臂，这股力量慢慢的渗透进你的身体里，带走了所有的疲劳与紧张。此时，你腰部的肌肉正在得到舒缓。你感觉到了什么？让感觉去到他们需要到达的地方，仔细探索。同时，尽情的享受这种感觉。\n你可以感受到你所吸入的每一口空气都能抚慰你身体上的每一块肌肉……每一块肌肉都舒服地舒展它们自己……而当你看到每一块肌肉都在放松的时候，你可以开始感觉到你手臂和腰部肌肉的那种舒适的感觉……这种舒适感在不断增加，散布到你身体的其他部位……\n现在，想象这束温暖的光，洒在你的双腿上，\n慢慢地，从大腿\n到小腿，\n最后，来到你的双脚。\n保持温和的、好奇的、慈爱的态度，并慢慢的感受、探索。\n留意腿部的感受，不管是什么，都请接纳他们。\n跟着自己感受，慢慢体验。\n随着气囊的涌动，你的呼吸也开始流向那个部位。\n吸气，\n呼气，\n\n接着，想象一下，你正躺在温暖的海滩上，被轻轻涌动的海浪包围。\n每一个波浪的起伏都带走你身体的疲惫，带来无尽的舒适与宁静。你将感受到一股如海浪般轻柔而有力的波动。这些波浪般的按摩动作将像海浪轻抚沙滩，层层递进，深入你的肌肉组织。\n\n放松你的身体，感受这股力量在你的肩部、背部、腰部和腿部缓缓流动，像海浪一样冲刷着你的疲惫与压力。\n\n\n\n不知道过了多久，声音和感觉渐渐淡了下去，波浪变得越来越轻柔，\n\n天边出现一抹嫣红。落日的余晖下，蜿蜒的海岸线一直延伸，向着远方，消逝在天际。偶尔划过天边的海鸟，一闪而过，只剩下那一双翅膀拂过的晚霞。\n远处，许多海豚在相继腾跃，留下美丽的抛物线。\n\n现在，感受自己的心跳，自己的血液循环，记住这份温暖。\n\n请把这份温暖的感觉留在这里,或留在身体需要的那个部位，并让它们慢慢地，温暖自己的全身,身体的各个部位,我们和它们充分融合在一起。\n\n再一次，注意一下自己的呼吸，均匀而舒畅地呼吸。\n缓慢地深深地吸气，感受腹部的微微隆起。缓缓地呼气，感受到自己的腹部在一点点地恢复平缓。感受呼吸的顺畅和身体的舒坦。\n此刻，引导语的陪伴即将慢慢褪去，音乐和海浪声会一直留在你的脑海里。你的意识在一点一点的变淡，身体变得越来越轻，越来越轻，越来，越轻。\n\n\n\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n接下来，你身下的床将慢慢推你起身，\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。当你感到悲伤、愤怒、烦躁和痛苦时，你也可以回来。\n在这个沉浸式疗愈空间中，耳界智能疗愈系统将营造一个属于你的最安全、最舒服的放松环境，帮助你回归到平静和放松的状态，建立心中的安全岛。你心中的平静和安全以及身体的轻盈与放松，都会牢牢地留在你的内心深处，你可以在任何时候回到这里，感受平静与放松。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n耳界earmersion，祝你拥有美好的一天，我们下次再会。', 55, '平静、接纳、释放', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000003', '睡眠区', '重回母体冥想（同气虚质）', '抱持感、安全感提升，缓解身体僵硬和紧张，腹部呼吸功能加强', 'Hi，你好~欢迎来到耳界沉浸式疗愈空间~在这里，您可以放下生活的忙碌，进入一个宁静放松的世界，此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐，深吸一口气，还可以闻到沁人心脾的香气。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n现在，你正在体验到的是零重力模式，你可以把身体调整到最舒适的状态，轻轻闭上眼睛，并在此安放你的内心。在接下来的30分钟里，您将在智能疗愈系统的帮助下，进行“重回母体冥想”的体验。你将重新回到妈妈的身体，感受安全与放松，让你在身处逆境时饱含爱的力量。这是一种神秘而独特的体验，你将被无尽的柔软包裹着。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受平静、治愈的美好体验。\n\n想象你已经进入到妈妈的身体里，\n\n你正自然地蜷曲在那儿。这是属于你的安全之地，调动你所有的知觉，融入到这个感受中。\n通过你的内心视觉环顾四周，你漂浮在一个充满液体的世界里，这些液体给你提供了营养和保护。在这个世界里，你可以随意的伸展四肢，无拘无束的放松你的身体。\n继续用你的内心视觉想象力再看上几秒。微微变化的光线透过你的眼睑，作用于你的松果体，让你看见想象中的画面。这个地方看起来怎么样？\n接下来，侧耳倾听，你听到什么？ 选择一些悦耳动人的声音听听，你甚至还可以听到妈妈的心跳声，这最原始的节奏，给与你安慰和力量。\n接着，看看能不能用你的身体触觉感知一些事物。你能感受到什么吗？选择场景中令你舒服的东西，用你的触觉想象力继续感受一会儿。\n现在，再用上几秒钟，允许自己沐浴在爱与善的温暖和悦纳中，就好像自己是一个待产的婴儿，被慈爱的母亲拥在腹中。这是你的秘密花园，感知在这里你是多么的安全和放松，\n再一次，注意一下自己的呼吸。吸气、呼气、吸气、呼气。\n伴随着腰腹部的气囊推压作用，继续保持均匀的呼吸，感受更深层次的能量流动。\n现在，将你的双手放在肚脐的位置，缓慢地深深地吸气，感受腹部的微微隆起。缓缓地呼气，感受到自己的腹部在一点点地恢复平缓。\n深深地，吸气，\n缓缓地，呼气。\n注意你的呼吸，要记住，这是一段有意识放松的时间，\n提醒自己保持清醒和警觉。\n仔细观察你的呼吸，\n你无需操纵它，只需要尽你所能去体会它，感觉它，跟随它\n不要对其进行任何评判。\n\n聆听自己的呼吸声，\n柔和微妙的声音是生命的流动。\n感觉气息通过鼻孔进入你的身体。\n接着进入胸部和腹部，\n再沿着它的路径通过鼻孔呼出。\n这个过程中，\n你可能会出现很多其他的身体感受、思绪或想法，\n都没有关系，\n我们要做的只是持续感受身体里的呼吸。\n\n\n接着，我们将跟随着身体和呼吸的波浪\n感受气息进入身体\n和气息离开身体。\n想象有一个波浪正在自上而下、自下而上地穿过你的身体，消除了你的紧张。\n吸气\n呼气\n吸气\n呼气\n\n感受每一次呼吸，能量在你体内流动，\n吸气时有一种充满活力的扩展。\n呼气，有一种完全释放的松弛感。\n\n请保持双手轻轻的放在你的腹部，用手感受你的腹部，探索轻柔呼吸的感觉。\n感觉你的腹部在每次吸气时抬高，呼气时下落。\n感受腹部的动作。\n\n轻轻吸气，慢慢地呼气\n在呼吸中，一点一点松解你的身体，不适与不安也随着呼吸渐渐远去。\n你感受到自己逐步放松，放松，变得那么的放松和专注……\n\n\n（停顿）\n\n\n不知道过了多久，声音和感觉渐渐淡了下去，波浪变得越来越轻柔。\n\n你继续在妈妈的肚子里漂浮着，尽你所能的体会这种漂浮感。\n\n你能感受到妈妈的呼吸、心跳和血液循环带给你的稳定和安全。这种熟悉的感觉构成了你和妈妈的特殊纽带。\n\n也许，你会发现自己的意识中出现了一些情绪，无论是什么，不用试图打断他们，只需要接纳，自然地流露出此刻的所有感受。\n\n现在，感受自己的心跳，自己的血液循环，并记住妈妈带给你的这份温暖。\n\n请把这份温暖的感觉留在这里,或留在身体需要的那个部位，并让它们慢慢地，温暖自己的全身,身体的各个部位,我们和它们充分融合在一起。\n\n再一次，注意一下自己的呼吸，均匀而舒畅地呼吸。\n缓慢地深深地吸气，感受腹部的微微隆起。缓缓地呼气，感受到自己的腹部在一点点地恢复平缓。感受呼吸的顺畅和身体的舒坦。\n\n此刻，引导语的陪伴即将慢慢褪去，音乐和羊水声会一直留在你的脑海里。你的意识在一点一点的变淡，身体变得越来越轻，越来越轻，越来，越轻。\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n接下来，你身下的床将慢慢推你起身，\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。当你感到悲伤、愤怒、烦躁和痛苦时，你也可以回来。\n在这个沉浸式疗愈空间中，耳界智能疗愈系统将营造一个属于你的最安全、最舒服的放松环境，帮助你回归到平静和放松的状态，建立心中的安全岛。你心中的平静和安全以及身体的轻盈与放松，都会牢牢地留在你的内心深处，你可以在任何时候回到这里，感受平静与放松。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n耳界earmersion，祝你拥有美好的一天，我们下次再会。', 40, '平静，包裹感，安全感，爱意', '深度镇静，爱的能量', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000004', '睡眠区', '痰湿质（稻田）', '化湿行气，减轻身体和精神的重浊感，提升精力与活力\n', '欢迎来到岳阳医院沉浸式音疗空间，希望接下来的音疗体验能给你带来愉悦、治愈的感受~在这里，你可以放下生活的忙碌，进入一个宁静放松的世界。此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n我们将通过音乐和引导语，结合床体气囊、频率振动和视觉通感联结你的身体感官；你会感受到，存在在你的耳蜗、皮肤上的气压、骨膜和内腔壁、乃至全身的感知神经，都在感受声波所带来的振动和压力变化，这种触振感知与听觉的联动，引发传到大脑的神经冲动，可以促进潜意识活动的释放，让大脑慢慢放松下来。\n在接下来的30分钟里，你将在沉浸式音疗空间中，进行“痰湿质”调理。在这个疗程中，你会来到丰收时节的稻田，进入稻田情景冥想，你还会听到和感受到舒曼波，这是一种自然界的频率，也被称为地球脑电波。舒曼波的频率与人大脑的alpha波频率相似，这种波段可以促进思维的清晰和减少焦虑感。\n现在，你只要放松的躺着即可，感受这一场温和而有效的恢复性体验。你将会注意到，在你舒服地躺在这里的时候，你的身体会产生某种愉悦的感受，这种舒服的感受可以给你带来足够的安抚。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受平静、治愈的美好体验。\n现在，请将注意力缓缓集中在呼吸上，每一次深深吸气时，仿佛有一股干爽的气流轻轻拂过身体，带着清爽的能量，慢慢渗透进四肢；每一次缓缓呼气时，就像把身体里那些沉重、黏腻的感觉轻轻呼出，让它们随着气息渐渐消散在空气中。\n想象着，深秋的上午，你来到了稻田中饱览丰收的景色，眼前是一大片成熟待收的稻田，稻株的叶子黄绿镶嵌，透出一种成熟稳重的色彩。金黄色的稻穗显露在顶端，挺拔又有点弯垂，这是饱满的谷子沉甸甸的造型。大片的稻田被阵阵吹过的秋风，掀起了如同海浪一般的波澜，起伏的稻浪发出动人的响声，这是大自然生命的气息，是丰收的硕果在向你呼唤。\n你沉浸在稻田秋色的氛围中，深深地吸了几口稻田中的空气，享受着稻子散发出的甜甜的芳香。你的四周都被稻子围着，身体被一层温和的清风吹拂，你已融入到与稻子一般的意境中。那些让你觉得沉重的湿滞感，正一点点被这清风带走。皮肤不再有黏腻的束缚，变得干爽而舒展；身体内部也仿佛被细细梳理过，不再有沉闷，每一个细胞都在呼吸中感受着轻盈与干爽。这种通透的感觉，正慢慢包裹着你，从指尖到脚尖，从胸腔到腹部，让你整个人都变得轻松、舒畅，仿佛卸下了身上的重担，只余下纯粹的清爽与自在。\n这是人和植物的融合，是人与自然的融合，你很满足，很充实，也很轻松……\n（以上5分钟左右）\n\n（纯音乐18-20分钟）\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。\n在这个沉浸式音疗空间中，我们调动了你全部的感知神经，让你的身体随着稻田的微风，变得更加轻盈，思维变得更加清晰。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n岳阳医院沉浸式音疗空间，祝你拥有美好的一天，我们下次再会。\n', 55, '平静、干爽、充实', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000005', '睡眠区', '阴虚质（溪水）', '滋阴降火，平复急躁情绪，引导内心回归宁静与清凉', '欢迎来到岳阳医院沉浸式音疗空间，希望接下来的音疗体验能给你带来愉悦、治愈的感受~在这里，你可以放下生活的忙碌，进入一个宁静放松的世界。此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n我们将通过音乐和引导语，结合床体气囊、频率振动和视觉通感联结你的身体感官；你会感受到，存在在你的耳蜗、皮肤上的气压、骨膜和内腔壁、乃至全身的感知神经，都在感受声波所带来的振动和压力变化，这种触振感知与听觉的联动，引发传到大脑的神经冲动，可以促进潜意识活动的释放，让大脑慢慢放松下来。\n在接下来的30分钟里，你将在沉浸式音疗空间中，进行“阴虚质”调理。在这个疗程中，你将在清凉如水的音乐中，感受你的身体。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受平静、治愈的美好体验。\n\n现在，轻轻地闭上眼睛，调整自己的呼吸。注意一下自己全身的感觉，伴随着均匀的呼吸，你正变得越来越放松，越来越平静，越来越安宁。\n想象着，你正沿着青石板路，漫步在一片郁郁葱葱的山林间。\n昨晚这里刚下过一场雨，此刻太阳刚刚升起，山间的晨雾还未散去，白纱般的柔柔地漂浮在空中，空气中还能闻到雨水浸湿的泥土味和树叶、花草的清香。\n不远处，有一条小溪从半山腰处，蜿蜒而下，时而湍急，时而静静地流淌，就像是一条轻盈的绸带，缠绕在空幽的山林间。慢慢地靠近，温暖的阳光洒在了水底的沙石上，一闪一闪的，溪里的小鱼一列列，一群群，欢快地畅游着。\n一阵微风吹过，带来了阵阵大自然的香气，林间的树叶窸窣作响，仔细聆听，远处还有鸟儿与小昆虫的和鸣。\n再一次感受一下自己的呼吸，深深地吸气，呼气。这里的一切是如此的幽静与安宁。此刻的你，享受这份直抵心间的清凉与滋润，让净化的心灵与美丽的自然融为一体。\n留意自己的感受，体验快节奏的工作和生活与这种带着大自然平静、滋养、治愈的氛围之间有何不同。尽你所能的体会身体的感觉、声音、想法和感受，保持开放的心态。均匀的呼吸，每一次呼吸都是烦恼的洗涤，不要着急，慢慢来。 \n（以上4分钟左右）\n\n（纯音乐18-20分钟）\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。当你感到紧张、愤怒、烦躁和痛苦时，你也可以回来。\n在这个沉浸式音疗空间中，智能疗愈系统将营造一个属于你的最安全、最舒服的放松环境，帮助你与“燥热感”和“焦虑感”解离，学习安抚和滋养自己。这种宁静与清凉也会一直围绕着你。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n岳阳医院沉浸式音疗空间，祝你拥有美好的一天，我们下次再会。', 65, '平静', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000006', '睡眠区', '湿热质（星空）', '清热祛湿，平复烦躁，引导情绪走向平和与清爽', '欢迎来到岳阳医院沉浸式音疗空间，希望接下来的音疗体验能给你带来愉悦、治愈的感受~在这里，你可以放下生活的忙碌，进入一个宁静放松的世界。此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n我们将通过音乐和引导语，结合床体气囊、频率振动和视觉通感联结你的身体感官；你会感受到，存在在你的耳蜗、皮肤上的气压、骨膜和内腔壁、乃至全身的感知神经，都在感受声波所带来的振动和压力变化，这种触振感知与听觉的联动，引发传到大脑的神经冲动，可以促进潜意识活动的释放，让大脑慢慢放松下来。\n在接下来的30分钟里，你将在沉浸式音疗空间中，进行“湿热质”调理。在这个疗程中，你将感受冬日星空下的风轻云淡，仿佛化身一颗星星，自由自在地漂浮在宇宙中，感受着身心的轻盈。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受平静、治愈的美好体验。\n轻轻地闭上你的眼睛。尝试做几次深呼吸，在吸气的时候，把你身上的疲劳、紧张以及头脑中一切不愉快的念头和烦恼统统聚集起来；而当你呼气时，将这些烦恼统统的呼出去。吸气，呼气。吸气，呼气。\n想象一下，你正漫步在冬日的白桦林间，头顶的星空熠熠生辉。空气中混合着雪后特有的清新气息，让每一次呼吸都变得格外干爽。放松你的身体和思绪，让心灵沉浸在这个静谧世界中，感受其中的温暖与安宁，任何人都不会打扰你。​\n抬头仰望，深邃的夜空中，你看见了无数闪烁着晶莹星光的星辰，它们正在缓慢地移动着。这些星星如同天上的小钻石，在夜空中静静闪耀，你的目光专注地跟随着这些星辰的轨迹逐渐转移。在这些星星的周围，你看到了些许微光，那是来自遥远宇宙深处的星云，这些星云的颜色各异，淡紫的、浅粉的、银白的、橘红的，给这片夜空增添了几分梦幻。这些色彩斑斓的星云与或近或远的星星，共同构成了一幅绚丽的星河图卷，在这里，你感受到宇宙的奥妙和美丽，内心变得自然而平静。​\n夜深了，寂静的夜晚里，星光如碎钻般洒落，点缀着漆黑的夜幕，让夜空变得更加璀璨和神秘。寒风轻轻吹过，摇曳的白桦枝彼此轻触，发出细微的响声，似乎在与天上的星辰诉说着它的故事。树枝在风中轻柔地舞动着，宛若大自然的舞者，偶尔，你能听到一些细微的动静，可能是一两只机灵的野兔在雪地里穿梭，给宁静的夜晚增添了一份生机和活力。​\n沉浸在当下的宁静氛围中，享受着星光的纯净和美丽，你遗忘了过往一切的烦恼与焦躁，感受着无比的舒适和放松。城市街道的喧嚣渐渐远离，繁杂的思绪也随之淡去，在这个瞬间，你仿佛与宇宙融为一体，感受到了生命的奇迹和宇宙的伟大。尽你所能地体会身体的感觉、声音、想法，保持开放的心态，当你感到有些朦朦胧胧的感觉飘移过来时，耳边的声音便离你渐行渐远，渐行渐远……\n\n（以上3-4分钟）\n（纯音乐18-20分钟）\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。当你感到沉重、愤怒、烦躁和痛苦时，你也可以回来。\n在这个沉浸式音疗空间中，我们运用感官意象，引导你关注身体所获得的力量，它帮助你在接下来的生活和工作中充满活力。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n岳阳医院沉浸式音疗空间，祝你拥有美好的一天，我们下次再会。\n', 60, '平静', '深度镇静', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000007', '睡眠区', '平和质（同森林冥想）', '采用自然之声维持平衡，维持与巩固身心和谐，提升幸福感，进行预防性的精神保健。', '欢迎来到岳阳医院沉浸式音疗空间，希望接下来的音疗体验能给你带来愉悦、治愈的感受~在这里，你可以放下生活的忙碌，进入一个宁静放松的世界。此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n我们将通过音乐和引导语，结合床体气囊、频率振动和视觉通感联结你的身体感官；你会感受到，存在在你的耳蜗、皮肤上的气压、骨膜和内腔壁、乃至全身的感知神经，都在感受声波所带来的振动和压力变化，这种触振感知与听觉的联动，引发传到大脑的神经冲动，可以促进潜意识活动的释放，让大脑慢慢放松下来。\n在接下来的30分钟里，你将在沉浸式音疗空间中，进行“平和质”调理。在这个疗程中，我们将来到静谧的山林深处，释放焦虑情绪，给身心来一场彻底的深呼吸，现在，把我们的身体调整到最舒服的姿势，缓缓地闭上双眼，吸气，让空气通过鼻腔吸入。呼气，感受气体通过口腔缓缓呼出。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受平静、治愈的美好体验。\n想象着我们正漫步在林间的小道上，柔和的光线从森林的空隙处渗透进来，斑驳的洒落在如绿毯般的草地上，一阵微风吹来，轻轻地拂过我的脸庞，几缕发丝随着那微风轻轻的飞扬。思绪也跟着飞啊飞啊，飞向那未知的远方。\n想象着蔚蓝的天空清澈的没有一丝云彩，深深的吸一口气，空气中还夹杂着野花的幽香。闻着这沁人心脾的幽香，仿佛身体也跟着坠入那一片片花的海洋，鸟儿在枝头欢快的鸣叫，用心倾听，远处还有小溪潺潺流水的声音。\n你被绿色的参天大树围绕着，温暖的春光照射下来，在地面上形成了深浅不一的光影。你闭上眼睛，深深地吸了一口气，你闻到了树木的味道、泥土的芬芳以及淡淡的花香，你喜欢这些混合在一起的味道，再次深深地吸一口气，大自然的味道让你感觉非常的治愈，你体会到了前所未有的放松。\n此刻，你沉浸这片美丽的大自然中，你的心里充盈着温暖与希望。你深深地被这一片美景治愈着。感受你身体的平衡与舒适，内在的平和与喜悦。你内在的平和，就像这森林一样，深邃而有力量。\n\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。\n在这个沉浸式音疗空间中，我们运用正念感恩和积极心理学的意象，以及自然之声，增强你的幸福感和对身心和谐状态的觉察力。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n岳阳医院沉浸式音疗空间，祝你拥有美好的一天，我们下次再会。', 55, '放松', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000008', '睡眠区', '阳虚质（同烛火冥想）', '升阳散寒，内在温暖，全神贯注地感受火元素带来的稳定和平和，沉浸在天然的疗愈能量中', '欢迎来到岳阳医院沉浸式音疗空间，希望接下来的音疗体验能给你带来愉悦、治愈的感受~在这里，你可以放下生活的忙碌，进入一个宁静放松的世界。此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n\n我们将通过音乐和引导语，结合床体气囊、频率振动和视觉通感联结你的身体感官；你会感受到，存在在你的耳蜗、皮肤上的气压、骨膜和内腔壁、乃至全身的感知神经，都在感受声波所带来的振动和压力变化，这种触振感知与听觉的联动，引发传到大脑的神经冲动，可以促进潜意识活动的释放，让大脑慢慢放松下来。\n在接下来的30分钟里，你将在沉浸式音疗空间中，进行“阳虚质”调理。在这个疗程中，你将跟随音乐，全神贯注地感受火元素带来的温暖和能量，帮助你沉浸在天然的疗愈能量中，逐渐恢复活力。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受温馨、治愈的美好体验。\n你的面前有一支正在燃烧的蜡烛，散发着温暖的光芒。\n现在，用鼻子深吸一口气，再缓缓地呼出，调整自己的呼吸，放松你的身体。\n闭上眼睛，再来一次，吸气，呼气。\n现在，将你的注意力全都集中在蜡烛顶端的烛火上，静静地观看。\n烛火是否正在微微舞动呢？投下摇曳的影子，忽明忽暗，柔和而宁静。\n\n静下心来，观察火的颜色，由外到内，他们的颜色是否有所变化呢？\n专注于烛火，无论它是什么颜色，什么形状，你只需要在它的伴随下，平稳地呼吸，感受和它在一起的此刻。\n火光点亮了不同角落，勾勒出空间的静谧。\n\n现在邀请你，慢慢再靠近它一些。你是否闻到一些火焰带来的气味呢？淡淡的飘进你的鼻腔。\n仔细聆听，或者你还能听到一些来自火焰燃烧的声响，那么细微却又充满生命力。\n在这柔和的光线中，静静感受它散发的温暖。这一抹温暖的光辉，照耀着你的面部，再蔓延到身体的每一个部位，你感觉到自己渐渐被暖意所包围着，舒缓了你所有紧张与疲惫。\n\n或许，你会有些思绪闪过，没有关系，不用对他们做出什么评判。\n只需要静静地继续观察这一束烛火，\n保持呼吸，全身心的投入这份静谧与温暖。\n\n在这过程中，无论你体验到什么，都会清楚地记在你的心里。\n此刻的你，在温暖和平和中，渐渐迎来睡意。\n\n（以上3-4分钟）\n（纯音乐18-20分钟）\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。当你感到悲伤、低落、消沉和无力感时，你也可以回来。\n在这个沉浸式音疗空间中，我们为你精心营造出一个温暖、平和的舒适环境，帮助你利用感官意象来提升内在温暖感和生命力。这种体验将会从内而外的包裹这你，会牢牢地留在你的内心深处，你可以在任何时候回到这里，感受平静与放松。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n岳阳医院沉浸式音疗空间，祝你拥有美好的一天，我们下次再会。', 50, '平静、温暖', '深度镇静', true, true, '18岁以上', '创伤后应激障碍，严重抑郁患者', '["创伤后应激障碍","严重抑郁患者","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000009', '睡眠区', '瘀血质（身体扫描）', '改变“瘀堵”认知，活血化瘀疏通身体堵塞，同时释放内心的烦躁与压力。', '欢迎来到岳阳医院沉浸式音疗空间，希望接下来的音疗体验能给你带来愉悦、治愈的感受~在这里，你可以放下生活的忙碌，进入一个宁静放松的世界。此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n\n我们将通过音乐和引导语，结合床体气囊、频率振动和视觉通感联结你的身体感官；你会感受到，存在在你的耳蜗、皮肤上的气压、骨膜和内腔壁、乃至全身的感知神经，都在感受声波所带来的振动和压力变化，这种触振感知与听觉的联动，引发传到大脑的神经冲动，可以促进潜意识活动的释放，让大脑慢慢放松下来。\n在接下来的30分钟里，你将在沉浸式音疗空间中，进行“瘀血质”调理。在这个疗程中，你将进行一次身体清扫，促进全身的血液循环，感受完全的放松。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受舒畅、治愈的美好体验。\n现在，从大脑开始，想象着一束温暖的光投射到你的头部，轻柔的探索，意识在大脑里流转，让大脑安静下来，放下各种念头，专注于现在的感受。\n光束继续下移，来到你的双肩，你会感受到肩胛部位受到智能气囊的推压作用。再一次，保持好奇心。现在这个部位有什么感受？你有没有任何收紧、舒展或其他感受？是否感受到在轻柔的气囊作用下，肩背部的僵硬、紧张得到了缓解。这种感觉延伸到你的脊柱，延伸到整个后背。仔细的感受被关照的感觉。\n放松你的身体，不要着急，多花几分钟，慢慢感受。\n吸气，\n呼气。\n\n现在，光束聚焦到你的腰部和双臂，这股力量慢慢的渗透进你的身体里，带走了所有的疲劳与紧张。此时，你腰部的肌肉正在得到舒缓。你感觉到了什么？让感觉去到他们需要到达的地方，仔细探索。同时，尽情的享受这种感觉。\n你可以感受到你所吸入的每一口空气都能抚慰你身体上的每一块肌肉……每一块肌肉都舒服地舒展它们自己……而当你看到每一块肌肉都在放松的时候，你可以开始感觉到你手臂和腰部肌肉的那种舒适的感觉……这种舒适感在不断增加，散布到你身体的其他部位……\n\n现在，想象这束温暖的光，洒在你的双腿上，\n慢慢地，从大腿\n到小腿，\n最后，来到你的双脚。\n保持温和的、好奇的、慈爱的态度，并慢慢的感受、探索。\n留意腿部的感受，不管是什么，都请接纳他们。\n跟着自己感受，慢慢体验。\n随着气囊的涌动，你的呼吸也开始流向那个部位。\n吸气，\n呼气，\n接着，想象一下，你正躺在温暖的海滩上，被轻轻涌动的海浪包围。\n每一个波浪的起伏都带走你身体的疲惫，带来无尽的舒适与宁静。你将感受到一股如海浪般轻柔而有力的波动。这些波浪般的按摩动作将像海浪轻抚沙滩，层层递进，深入你的肌肉组织。\n\n放松你的身体，感受这股力量在你的肩部、背部、腰部和腿部缓缓流动，像海浪一样冲刷着你体内的淤堵，带走了你的疲惫与压力。\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。当你感到麻木、疼痛、闷堵和痛苦时，你也可以回来。\n在这个沉浸式音疗空间中，我们会精心营造出一个属于你的最安全、最舒服的放松环境，帮助你感受身体的流动和顺畅。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n岳阳医院沉浸式音疗空间，祝你拥有美好的一天，我们下次再会。', 50, '放松', '平静放松', true, false, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000000a', '睡眠区', '气郁质（花丛）', '疏肝解郁，开阔心胸，引导情绪从忧郁转向开朗', '欢迎来到岳阳医院沉浸式音疗空间，希望接下来的音疗体验能给你带来愉悦、治愈的感受~在这里，你可以放下生活的忙碌，进入一个宁静放松的世界。此刻，你正舒适的躺在温暖的床上，头部轻轻落在柔软的枕面上，眼前是一片柔和的光线，耳边传来舒缓的音乐。这些感受温柔的包裹着你，帮助你调动所有的知觉，展开这场独一无二的正念冥想体验。\n我们将通过音乐和引导语，结合床体气囊、频率振动和视觉通感联结你的身体感官；你会感受到，存在在你的耳蜗、皮肤上的气压、骨膜和内腔壁、乃至全身的感知神经，都在感受声波所带来的振动和压力变化，这种触振感知与听觉的联动，引发传到大脑的神经冲动，可以促进潜意识活动的释放，让大脑慢慢放松下来。\n在接下来的30分钟里，你将在沉浸式音疗空间中，进行“气郁质”调理。在这个疗程中，你将来到一片宁静的花丛中，体验一场愉悦和舒畅的恢复性体验。\n如果你准备好了，你可以尝试进入接下来的3D沉浸式音乐冥想，享受轻松、治愈的美好体验。\n想象一下，你正躺在一片缤纷灿烂的花海中。被阳光晒过的土壤是温暖的，你的背部感受着身下厚实的土地。环顾四周，此时映入你眼帘的，是一片非常特殊，又万紫千红的景色。离你头部最近的，都是盛开着的花朵，花的颜色很多，有大红的，粉红的，金黄的，鹅黄的，有的花还包含多种颜色，阳光透过层层的花瓣，色彩变得透明而又厚实，似乎都成了玉雕的工艺品。用手轻轻地抚摸花瓣，花瓣的表面光滑柔嫩。此刻，透过花朵之间的间隙，你还看到了其他绽放的花朵，虽然不一定能说得上花名，但花朵的形态、色彩，都是多么的美丽和动人。\n此时，你听到了嗡嗡的声音，这是飞来采蜜的蜜蜂，他们停留在花蕾上静静地采蜜，是那样的耐心和专注。你仿佛也品尝到了，这份甜蜜的滋味。远处传来了细细的鸟鸣声，与耳边的蜜蜂舞鸣声，构成了天然交织的音律。深深的呼吸一下这里的新鲜空气，这里的每一缕风都掺杂着繁花的味道，这是一种带着甜味的清淡香气。\n感受自己，就像是自然的一部分，只有躺在花丛中，才能享受得到如此美妙的春色气息。春日午后的和煦阳光，溶解了满身的疲累，沐浴在温暖的日光中，你的身体变得富有生命力，就像一束被阳光眷顾的花朵。微风拂过你的身体，卷走过往一切的烦恼与焦躁，你感觉到自己的身体越来越轻，越来越轻，化作一片白云，与蓝天融为一体。车水马龙的喧嚣渐渐远离，繁杂的思绪也随之淡去……\n（以上4-5分钟）\n（纯音乐18-20分钟）\n\n现在，跟我一起，从5数到1。当我们数到1的时候，你会感到大脑十分清醒，精神格外清爽，身体充满了活力。\n5 慢慢把意识专注到当下\n4睁开眼睛，动一动手指和脚趾\n3轻轻舒展一下身体\n2深深地吸气，呼气\n1完全清醒过来                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            \n当你完成这些步骤的时候，可以结束这段体验，慢慢把意识回到当下。你可以默默地再次体会这个过程，你会感到一种轻盈和焕发的感觉，仿佛身体重新注入了活力。\n请你带着这份轻松和愉悦，回到日常生活当中。当你想获得这种感觉的时候，记住你随时可以回到这里。当你感到悲伤、郁闷、纠结和痛苦时，你也可以回来。\n在这个沉浸式音疗空间中，舒缓而开阔的音乐，帮助你安放好你的身体和情绪。所有的郁闷和压抑，都在缤纷灿烂的花丛中逐渐消散，你会感到前所未有的轻松和舒畅。\n此刻只是变化的开端，随着不断深入和持续的练习，你的内在能量将会慢慢复苏、生长，变得绚烂多彩。\n岳阳医院沉浸式音疗空间，祝你拥有美好的一天，我们下次再会。', 40, '平静、愉悦、治愈、舒畅', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000000b', '睡眠区', '腿部按摩', '让人在短时间内投入音乐当中，清灵的音符，让精神世界从无序到有序，让人远离烦躁的生活琐事，把凌乱的思绪梳理干净。', '/', 60, '平静', '深度镇静', false, false, '18岁以上', NULL, '["听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000000c', '睡眠区', '体感音波', '让人在短时间内投入音乐当中，清灵的音符，让精神世界从无序到有序，让人远离烦躁的生活琐事，把凌乱的思绪梳理干净。', '/', 40, '平静', '深度镇静', false, false, '18岁以上', NULL, '["听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000000d', '睡眠区', '腰部按摩', '让人在短时间内投入音乐当中，清灵的音符，让精神世界从无序到有序，让人远离烦躁的生活琐事，把凌乱的思绪梳理干净。', '/', 70, '平静', '深度镇静', false, false, '18岁以上', NULL, '["听力损失","耳鸣","急性精神病状态","严重心律失常","身体疼痛/疾病","创伤患者"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000000e', '情志区', '海洋冥想', '自然情境深度减压', '想象着阳光，沙滩以及深邃无边的海洋……\n行走在沙滩上，脚底感受着细细的，温暖的沙砾。微风轻轻地拂过我的脸庞。海浪沾湿我的脚背。那一抹清凉，是大海，爱的馈赠。近处的浪花不时地涌上沙滩，前后追逐着，发出阵阵的欢快声。\n轻轻地，乘着海边的一叶渔船，伴随着海风，飘啊飘啊。温暖的阳光洒在身上，感受到自己的身体越来越轻，越来越轻……\n不知道过了多久，全部的声音渐渐淡了下去。天边出现一抹嫣红。落日的余晖下，蜿蜒的海岸线一直延伸，向着远方，消逝在天际。偶尔划过天边的海鸟，一闪而过，只剩下那一双翅膀拂过的晚霞。远处，许多海豚在相继腾跃，留下美丽的抛物线。\n请把右手放在左手的手腕上，或把左手放在右手的手腕上。现在，感受自己的心跳，自己的血液循环，记住这份温暖。\n请把这份温暖的感觉留在这里,或留在身体需要的那个部位，并让它们慢慢地，温暖自己的全身,身体的各个部位,我们和它们充分融合在一起。\n再一次，注意一下自己的呼吸，均匀而舒畅地呼吸。\n缓慢地深深地吸气，感受腹部的微微隆起。缓缓地呼气，感受到自己的腹部在一点点地恢复平缓。此刻，我们会感受到呼吸的顺畅和身体的舒坦。', 55, '放松、接纳', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000000f', '情志区', '森林冥想', '自然情境深度减压', '想象着我们正漫步在林间的小道上，柔和的光线从森林的空隙处渗透进来，斑驳的洒落在如绿毯般的草地上，一阵微风吹来，轻轻地拂过我的脸庞，几缕发丝随着那微风轻轻的飞扬。思绪也跟着飞啊飞啊，飞向那未知的远方。\n想象着蔚蓝的天空清澈的没有一丝云彩，深深的吸一口气，空气中还夹杂着野花的幽香。闻着这沁人心脾的幽香，仿佛身体也跟着坠入那一片片花的海洋，鸟儿在枝头欢快的鸣叫，用心倾听，远处还有小溪潺潺流水的声音，想象古诗里的“小桥．流水．人家”。来到溪边，俯身捧起一捧清澈的溪水，让这清凉的溪水滋润我们的脸部，抹去岁月留下的痕迹，回复少女般白皙的容颜，让这清凉的溪水经我们的口、舌、喉，沉入我们的肺腑，滋润我们全身的肌肤。用心去体会，感觉宇宙之间所有的能量慢慢的注入体内的每个角落，滋养我们身体的所有细胞。      \n带着这样的感觉，让我们再一次回到静谧的山林，请将双手放在自己觉得舒服的地方，让自己完全的放松下来。均匀的呼吸，感受空气在我们的体内流动，身体越来越轻，越来越轻，仿佛将要随着那潺潺的溪水缓缓流走，流向我们理想的心灵居所。\n缓慢地深深地吸气，缓缓地呼气，感受舒畅和平静。', 55, '放松', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000010', '情志区', '花丛冥想', '自然情境深度减压', '现在，想象着你正躺在花农的花圃中。被阳光晒过的土壤是干热的，你的背部感受着地热反射的暖洋。你的头部几乎已贴近在花丛之中。此时映入你眼帘的是一种非常特殊的万紫千红的景色。离你头部最近的都是盛开的郁金香，花的颜色很多，有大红的，粉红的，金黄的，鹅黄的，还有黑色的。有的花朵包含多种颜色，十分神奇。阳光透过层层的花瓣，色彩变得透明而又厚实，似乎都成了玉雕的工艺品。透过郁金香之间的间隙你还看到了其他绽放的花朵，虽然不一定说得上花名，但花朵的形态、色彩都是多么的美丽和动人。\n此时，你听到了嗡嗡的声音，这是飞来采蜜的蜜蜂。他们停留在花蕾上静静地采蜜，是那样的耐心和专注。这些小蜜蜂传递给你的是一种生物和自然的能量。远处传来了细细的鸟鸣声，这与耳边的蜜蜂舞鸣声构成了天然交织的音律，只有躺在花丛中才能享受得到如此美妙的春色气息。\n一阵风吹来，你闻到了一阵桂花香，这不是幻觉，是春风把远处四季桂的幽香飘带了过来。虽然郁金香没有诱人的花香，但花丛中的特殊清香同样芬芳迷人。此刻是那么的平静，那么的安宁，那么的令人神往，在这甜甜的沉思中，睡意也已经离你越来越近了。', 40, '平静、愉悦、治愈、舒畅', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000011', '情志区', '烛火冥想', '自然情境深度减压', '你的面前有一支正在燃烧的蜡烛，散发着温暖的光芒。\n在接下来的时间中，你将跟随音乐，全神贯注地感受火元素带来的稳定和平和，帮助你沉浸在天然的疗愈能量中，舒适地睡去。\n现在，用鼻子深吸一口气，再缓缓地呼出，调整自己的呼吸，放松你的身体。\n闭上眼睛，再来一次，吸气，呼气。\n现在，将你的注意力全都集中在蜡烛顶端的烛火上，静静地观看。\n烛火是否正在微微舞动呢？投下摇曳的影子，忽明忽暗，柔和而宁静。\n静下心来，观察火的颜色，由外到内，他们的颜色是否有所变化呢？\n专注于烛火，无论它是什么颜色，什么形状，你只需要在它的伴随下，平稳地呼吸，感受和它在一起的此刻。\n火光点亮了不同角落，勾勒出空间的静谧。\n现在邀请你，慢慢再靠近它一些。你是否闻到一些火焰带来的气味呢？淡淡的飘进你的鼻腔。\n仔细聆听，或者你还能听到一些来自火焰燃烧的声响，那么细微却又充满生命力。\n在这柔和的光线中，静静感受它散发的温暖。这一抹温暖的光辉，照耀着你的面部，再蔓延到身体的每一个部位，你感觉到自己渐渐被暖意所包围着，舒缓了你所有紧张与疲惫。\n或许，你会有些思绪闪过，没有关系，不用对他们做出什么评判。只需要静静地继续观察这一束烛火，保持呼吸，全身心的投入这份静谧与温暖。\n在这过程中，无论你体验到什么，都会清楚地记在你的心里。\n此刻的你，在自然和平和中，渐渐迎来睡意。', 50, '平静、温暖', '深度镇静', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000012', '情志区', '温泉水疗音乐冥想', '水流的声音能够有效防止压力的囤积缓解焦躁情绪，将音乐融入温泉的声音效果中，还原自然界原本的声音状态，同时在语言的引导下，将注意力转移到听觉上来，减轻身体其他部位的疼痛。同时，水流产生的alpha波，可以缓解负面情绪使大脑快速放松和平静下来。', '现在，缓缓地闭上双眼，放松你面部的肌肉,舒展眉心,放松你的身体。看看是否能带着觉察来感受呼吸，\n觉察自己来到一处深山中的室外温泉\n这是一个你可以感到安全并且放松的地方\n空气中弥漫着山间清新的植被味道。你禁不住深深的吸一口气，生命的气息流入了你的心田。缓缓地呼一口气，将体内郁积的污气、浊气向外排出，让你的身体得到了净化。在宁静的环境中，你聆听着温泉水潺潺的流动声，柔和又缓慢。那是大自然本身的节奏，让你从紧张和焦虑的负面情绪中解脱出来。听着耳边的流水声，你不由自主地开始跟随这舒缓的节奏呼吸。吸气，温暖的泉水仿佛流入了你的身体里；慢慢地呼气，带走了身上的疲惫与紧绷。你感觉到前所未有的舒适和放松，身心自由而轻盈。\n\n此刻，\n安定你的身体，\n安定全身的皮肤，\n安定你的心，\n安定觉察本身，就像是回到家一样\n\n温泉之上氤氲着一片雾蒙蒙的蒸汽，如同一层轻柔的薄纱笼罩在水面上，你感觉到自己仿佛来到了仙境中，脑海里繁杂的思绪也随着池中的袅袅雾气飘散。\n微风吹过，雾气随之向周围飘散，有一些雾气轻柔地往你的方向吹来，丝缎般抚上了你的皮肤。你顺着这些水雾飘散的方向，缓缓地步入了水中。\n泉水柔和地紧贴着你的全身，促进了你体内的血液循环。温暖的水流轻轻地按摩你的身体，让你全身的肌肉逐渐地松弛下来，所有的紧张与疲惫都被消溶在温泉之中。当你完全地浸泡在温泉中时，你感觉身体在水中好像被托起，似乎又回到了母亲温暖的怀抱中。\n\n保持这样的觉察\n\n觉察可以涵容\n不舒服和不想要的感受\n\n至少在此时此刻\n试试看不推开、不压抑\n\n不急着解决\n而是去承接\n\n并且在觉察中保持安定的内心\n\n\n如果你发现思绪有些游移                          \n没有关系\n这就是自然而然会发生的事情\n\n就像是温泉上漂浮的水汽\n会有波动和飘移\n但是如果沉入泉水里\n水底下就只是平缓的起伏和平静\n这就和思绪的活动一样\n\n如果你觉得疼痛实在是太难受了\n你在想我不确定我是否要做这个练习\n或者其他念头\n这些都只是念头\n会随着情绪来了又走\n你不需要将这些念头推开\n或是想要做些什么\n只需要简单的在泉水声温暖的包围下感受此时此刻\n\n把注意力集中在腹部，在身体上\n感受呼吸的起伏\n一进一出\n\n\n\n专注地享受着当下这片属于你的世外桃源。随着微风轻轻吹过，你看到近处的水面上泛起层层的涟漪，一圈一圈的蔓延开来。抬头远望，远处的山峦仿佛与天空融为一体，你不由自主地沉浸在周围的美妙景色中。你多么想时间能在这里停下脚步，让你有足够的时间去享受这份宁静和美好。\n此刻\n并没有需要体会到什么特殊的感觉\n没有要去什么地方\n没有要做什么事\n也没有要达到什么目标\n就只是在当下 \n\n就只是在当下 \n\n\n此刻，让我们结束这段体验。你可以跟随着音乐，慢慢把意识拉回到当下，你可以缓缓地睁开眼睛，整理一下思绪，慢慢的起身，不要着急，音乐会一直围绕着你。', 50, '温暖、舒缓', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000013', '情志区', '方形呼吸节奏练习', '呼吸疗法可以有效减少去甲肾上腺素和皮质醇等压力激素的产生，增加褪黑素的释放，改善疲惫、焦虑等情绪问题。当呼吸渐渐与音乐同频时，能慢慢感受到放松和平静，逐渐产生困意。', '现在，找一个让自己觉得舒服的椅子坐下或者在床上躺下，并确保自己在接下来的时间中不会被打扰。无论你是坐着还是躺着，让我们一起开始今天的练习，如实的感受此时此刻。\n\n微微闭上双眼，有意识地，向外展开肩膀，深深地吸一口气，再慢慢地呼出。同时放松身体。在刚开始的一会儿，你会发现，你的身体在一呼一吸的过程中，慢慢沉静下来，你会感觉到身体的放松，虽然静止不动，但却不是瘫软无力的。\n\n首先你可能会发现，你的身体正在呼吸。\n身体的呼吸不是简单的吸气和吐气，而是气流经由口鼻直达肺部，延伸到你的各个器官、细胞。\n呼吸是让我们维持生命的过程，尝试体会气息进出时身体的感觉。  \n你可以呼吸的过程想象成一个方形，方形的每一条边代表一呼一吸的过程\n\n带着好奇心专注在当下的一呼一吸，觉察呼吸时的感觉。\n感受气息进入身体，又离开身体\n这个过程中在某些时候，你可能会觉得有一些困难，\n杂乱思绪不断地冒出来，烦扰你此时的平静状态，\n甚至把你引向某一个思绪里，衍生出许许多多的内容和场景。\n\n也可能出现很多其他的身体感受\n身体可能会有很不舒服、甚至是疼痛的感觉\n\n在这个练习中，我们不需要逃避这些感觉\n我们要做的只是持续感受身体里的呼吸\n看看我们是否可以跟随着呼吸的波浪\n感受气息进入身体\n和气息离开身体\n\n看看身体的哪个部位最明显的感知到呼吸，\n让它去成为觉察中心\n\n\n或许是在腹部感觉比较明显\n\n或者是在鼻腔内\n\n也或许是在躯干比较能感觉到呼吸\n包括胸部,肺部\n不论是哪个部位\n让我们把注意力放到在呼吸上\n跟随着气息进入身体\n带着觉察\n也跟随着气息离开身体\n一个气息，接着一个气息，再接着一个气息\n直接体会当下的所有感觉\n\n\n\n随着你持续感受气息进入身体                \n和气息离开身体的感受\n以及和呼吸相关的身体感受和变化 \n\n这么做的时候                             \n身体可能会出现很多其他的感觉\n有时感觉很不舒服\n\n没关系，如实的感受这所有的感觉\n如果感觉强烈到把注意力带走了\n可以将注意力放在不舒服的地方片刻\n但是如果没有这么不舒服\n试试看是否能将注意力放在腹部\n或者在鼻腔内\n或者任何呼吸感觉明显的身体部位\n带着觉察\n\n\n你可能会发现\n你的思绪开始漂移\n甚至忘记自己正在练习\n\n\n没有关系，你可以改变一下坐姿，稍加振作，并把注意力拉回到呼吸上，试着从一个高度去整理冒出来的这些想法，稳定自己平静专注的状态。仅仅是观察这些思绪和感受，给自己一点时间。\n一旦你发现                          \n心已经飘走\n注意力没有在呼吸上时\n你就已经把心带回来了\n所以完全不需要\n批评或责备自己\n就单纯地将自己再一次地带回此时此刻\n感受气息进来，气息离开\n以及气息在身体里的感受\n\n\n\n然后看看是否可以                        \n安住在觉察中\n\n就在此时此刻                             \n在这个我们称为\n“当下”的此时此刻\n\n或许可以允许自己                             \n在这个过程中并没有要去哪里\n没有要体验什么特殊的状态\n或者是成为更好的自己\n而是和自己同在\n和此时此刻的自己同在\n\n我们唯一拥有的这个时刻\n就是此时此刻\n\n此刻\n并没有需要体会到什么特殊的感觉\n没有要去什么地方\n没有要做什么事\n也没有要达到什么目标\n就只是在当下 \n\n就只是在当下 \n\n\n此刻，让我们结束这段体验。你可以跟随着音乐，慢慢把意识拉回到当下，你可以缓缓地睁开眼睛，整理一下思绪，慢慢的起身，不要着急，音乐会一直围绕着你。', 115, '积极，欢快', '中度激活', true, false, '18岁以上', '精神分裂症患者，创伤后应激障碍，物质滥用患者', '["精神分裂症患者","创伤后应激障碍","物质滥用患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000014', '情志区', '穿越山林音乐冥想', '开始一次登山之旅，利用山的形象，点亮前方灯塔，无条件接纳自己，同时，借助山的能量支撑自己，使自己能够以一颗澄澈之心对待当下，进入宁静、智慧的状态。使自己不会陷于困难中，而是勇敢面对它，把它当做是另一种幸运的开始。', '现在，找到一个让自己觉得舒服的地方，坐下来。缓缓地闭上双眼，放松你面部的肌肉,舒展眉心,放松你的身体。\n\n尝试在心中勾勒出，一片昏暗的森林，以及远处一座心中最美的高山……我们就要穿过这片树林，登上山顶。\n你背着双肩包，行走在这片昏暗的树林中，没有温暖的阳光，身上感觉阴冷冷的。周围很安静，只有枝头，零星的鸟儿与我作伴。一阵风轻轻吹过，树叶窸窣作响。\n此刻，你感受到了什么。\n这段旅途，就像你的生命，不是一帆风顺的幸福之旅，而是在光明与黑暗的模式中切换。\n你慢慢地向着前方那一点微弱的光亮，走啊，走啊。偶尔停下来，你发现那座山离你越来越近，越来越近。直到，你来到了山脚下。\n现在，把注意力集中在这座山的形象上。留意它的形状，它的高度，山上存在的各种植物和动物。观察它的雄伟与宁静。你只是静静地观察它。并尝试，将自己幻化成这座山的形象，稳定，沉静。无论白天或者黑夜，春、夏、秋、冬，日复一日，鸟儿歌唱、树木生长，溪水潺潺，宁静中蕴含万变。\n\n接纳事情原本的样貌\n只是静静的观察\n就像你观察四季和日夜那样\n\n不表示你需要喜欢这些事情 \n有时候这些事让人厌恶、害怕，心碎\n而我们需要去面对\n并维持明智的关系\n\n这确实可以帮助摆脱压力、疼痛和疾病所带来的感受\n以及自己在心中扩大这些感受的倾向\n\n观察自己是不是有一些无意识的念头和情绪反应\n并试图将注意力拉回到山的形象上，\n\n\n这就像观察天空中的白云随风飘走那样\n不断往坏的方面想的冲动\n也会被破解\n这座山也就在那里\n安稳、沉静\n\n此时你再度安住在全然的觉察中\n没有陷落在自我的故事中\n想像状况会变得多糟，多可怕\n无论状况多糟多可怕\n这个故事只是你很小很小的一部分\n所以让我们安住在广阔且无边无际的觉察中\n\n\n\n再一次，注意一下自己的呼吸，是否柔和顺畅。\n感受此刻，借助山的能量支撑自己，使自己能够以一颗澄澈之心对待当下：你看清自己每时每刻的想法与感受、看清自己的执念、疑惑、看清发生在自己身上的每一件事情。面对它们，尊重它们，感受它们，尝试接纳，进入宁静、智慧的状态。不要陷于困难中，勇敢面对它，把它当做是另一种幸运的开始。\n\n在觉察中\n你已经来到了山顶\n就在此时此刻\n允许所有事情如其所是的存在\n\n每天持续的用这样的方式练习\n我很肯定你会发现\n和自身深层的美好\n越来越亲密\n很多时候我们很难真正看见自己\n总是希望事情有所不同\n或者想让事情变成另一种方式\n而忽略能觉察到\n当下的这个奇迹\n其实是很宝贵的\n而且只有在觉察内才能获得\n\n此刻，让我们结束这段体验。你可以跟随着音乐，慢慢把意识拉回到当下，你可以缓缓地睁开眼睛，整理一下思绪，慢慢的起身，不要着急，音乐会一直围绕着你。', 90, '中性', '轻度激活', true, true, '18岁以上', '精神分裂症患者，创伤后应激障碍，物质滥用患者', '["精神分裂症患者","创伤后应激障碍","物质滥用患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000015', '情志区', '温暖花丛音乐冥想', '来到春日午后的花圃中，进入花丛情景冥想，感受微观世界中的温暖与宁静。专注于一些内心景象,尤其是生活中的美好景象，对于减缓负性情绪非常有用，这些美好的景象能减轻焦虑，甚至让人平心静气，进入放松以及积极的状态，收获愉悦感和成就感。', '现在，缓缓地闭上双眼，放松你面部的肌肉,舒展眉心,放松你的身体。\n想象着你正躺在花农的花圃中。被阳光晒过的土壤是干热的，你的背部感受着地热反射的暖洋。你的头部几乎已贴近在花丛之中。此时映入你眼帘的是一种非常特殊的万紫千红的景色。离你头部最近的都是盛开的郁金香，花的颜色很多，有大红的，粉红的，金黄的，鹅黄的，还有黑色的。有的花朵包含多种颜色，十分神奇。阳光透过层层的花瓣，色彩变得透明而又厚实，似乎都成了玉雕的工艺品。透过郁金香之间的间隙你还看到了其他绽放的花朵，虽然不一定说得上花名，但花朵的形态、色彩都是多么的美丽和动人。\n\n此时，你听到了嗡嗡的声音，这是飞来采蜜的蜜蜂。他们停留在花蕾上静静地采蜜，是那样的耐心和专注。这些小蜜蜂传递给你的是一种生物和自然的能量。  \n远处传来了细细的鸟鸣声，这与耳边的蜜蜂舞鸣声构成了天然交织的音律，只有躺在花丛中才能享受得到如此美妙的春色气息。\n\n\n觉察此刻的感受 \n\n无论感受到舒服的                 \n不舒服的\n都不是那么重要\n或许有些事情真的让人很不舒服甚至很痛苦\n但这都是生命的一部分\n关键是如何和这一切有明智的关系\n在我们唯一拥有的这个当下\n永远只会有这一个当下\n\n\n此刻，你是无比清醒的\n你正在对自己的内心做清理和挖掘\n清理出所有的不适\n挖掘出内在最深层最美好的爱意\n\n\n在这个过程中，\n你会去成为更好的人\n能更有效处理疼痛                             \n\n\n邀请你去体验这种自身的美好\n体验你自身的圆满\n只要做你自己就好\n在这个你唯一拥有的当下\n\n一阵风吹来，你闻到了一阵桂花香，这不是幻觉，是春风把远处四季桂的幽香飘带了过来。虽然郁金香没有诱人的花香，但花丛中的特殊清香同样芬芳迷人。此刻是那么的平静，那么的安宁，那么的令人神往。\n\n在觉察中\n你已经沉醉在花香中\n就在此时此刻\n允许所有事情如其所是的存在\n\n每天持续的用这样的方式练习\n我很肯定你会发现\n和自身深层的美好\n越来越亲密\n很多时候我们很难真正看见自己\n总是希望事情有所不同\n或者想让事情变成另一种方式\n而忽略能觉察到\n当下的这个奇迹\n其实是很宝贵的\n而且只有在觉察内才能获得\n\n此刻，让我们结束这段体验。你可以跟随着音乐，慢慢把意识拉回到当下，你可以缓缓地睁开眼睛，整理一下思绪，慢慢的起身，不要着急，音乐会一直围绕着你。\n\n', 40, '平静、愉悦、治愈、舒畅', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000016', '情志区', '暖阳安驻', '吉他，中低频饱满的音色建立安全感，营造阳光的温暖感，叠加Alpha 脑波能减少杂念，让意识更专注于温暖阳光的正向暗示，促进身体积极响应与接纳这份滋养与修护。', '第一周期（第1-3周）：暖阳安驻 (Grounding & Safety)\n\n\n[声音：温暖的弦乐铺底，深沉、稳定的长音，每分钟60拍的节奏基底，模拟静息心率]\nHi你好，欢迎来到这里，这是完全属于你的、宁静放松的珍贵时光。现在，请找一个最舒适的姿势，无论是靠坐着还是半躺，将身体的重量完全交付给你身下的座椅或床铺。感受一下背部的支撑，它是那么稳固，就像大地一样，稳稳地承托着你。在这里，你是绝对安全的。\n\n或许此刻，治疗留下的印记还带着隐隐的牵扯感，对未来的担忧可能像细碎的云絮掠过心头，对身体变化的敏感也悄悄藏在某个角落。这些感受都真实存在，像你身体的一部分，无需回避，不必评判——在这里，这些感受都被允许存在，它们和你的呼吸、心跳一样，值得被温柔对待，都将被这片宁静稳稳接住。\n\n[声音：伴随轻柔的风吹草地自然声]\n现在，请闭上双眼，想象自己正置身于一片开阔、柔软的草地上。此时是初春的午后，阳光正好。你能感受到那温暖的阳光，正温柔地洒在你的头顶、肩膀和手臂上。这股暖流，正顺着你的毛孔，轻柔地渗入体内，像一层金色的毯子，将你温柔地包裹起来。\n\n你的呼吸平稳而深长。\n温柔地吸气，感受胸腔的扩张\n缓慢地呼气，肩膀下沉，背部松开\n吸气，感受新鲜氧气的进入\n呼气，释放所有的紧张\n再一次吸气，你感受到了阳光的活力\n呼气，深处的肌肉都随之舒展、放松\n\n随着每一次的呼吸，阳光般的暖流在你的血管中轻柔地流淌，你感受到了暖意洒遍了全身。这股充满生机的能量缓慢而温柔地流动，精确地抵达那些需要特别关注的部位，带来舒缓与滋养。在你体内，那团曾经混乱的、凝结如冰块般的积聚物，此刻被这股源源不断的温热能量所包围，开始逐渐消融、变小，仿佛冬雪在暖阳下悄然融化。这份温热的能量，为它所触及的每一处，都带来了深层的安宁与修护。\n\n此时，你是安全的，你是被保护的。你的内心感到无比平静，不再有任何担忧与不安。你的身体也正在积极响应与接纳这份滋养与修护，每一个细胞都在放松、舒展。你与周围的世界和谐共处，大地坚实而稳定地托举着你，阳光柔和而温暖地照耀着你，一切都显得如此宁静而美好。\n带着这份深沉的安全感和暖意，你已经准备好，以最放松、最安稳的状态，去度过这美好的一天。你做得很好，一切都在稳步向好。\n\n', 52, '安全、平静', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000017', '情志区', '清泉流转', '竖琴，模拟水流的流动性', '第二周期（第4-6周）：清泉流转 (Flow & Purification)\n\n\n[声音：印象派风格（如德彪西风格），结构松散，流水声，无明显重拍。]\nHi你好，欢迎来到这里。现在的你，正在经历一场伟大的更新。或许有时你能感受到身体中一些特别的信号，可能是轻微的胀满，或许是隐隐的搅动。不必急着推开这些感觉，也不用评判它们是否“应该”出现。这是身体在治疗旅程中发出的温柔低语，是细胞在努力适应、在修复、在积蓄重新舒展的力量。试着找一个最让你感到舒服的姿势，让我们把注意力带回到身体的内部，去感受那里的流动与生机。\n\n [声音：清澈的山间溪流，清脆、具有流动感的水流声，水晶钵的高频泛音]\n请闭上双眼，想象自己正站在一道清澈见底的山间清泉之下，这股泉水源自纯净的高山，带着甘甜的气息，正源源不断地滋养着你。轻风拂过你的面庞，你感受到了一股温柔而纯净的能量缓缓流入你的身体。\n试着把呼吸轻轻送向你的腹部，让我们做一次深层的净化呼吸。\n请用鼻子深深吸入这股清爽的水汽... 屏住呼吸 （约2秒）.. 然后用嘴巴缓缓吐气，发出“呼——”的声音。\n感受每一次吸气时，腹部微微鼓起的包容；每一次呼气时，紧张感如薄雾般悄悄散开。\n再一次，鼻子吸气，屏住呼吸，嘴巴缓缓吐气……这里没有对抗，只有温柔的拥抱。\n吸气，屏气，吐气……身体在接纳中，慢慢找回属于它的平衡与安宁。\n\n随着呼吸，想象这股清凉的泉水，从你的头顶缓缓流下。它顺着你的喉咙，温柔地滑过食道，来到了你的胃部。它像一层清凉的保护膜，抚平了胃壁上所有的褶皱和燥热。你的胃部现在变得清凉而舒适，就像被雨水冲刷过的玉石，光滑且洁净。\n\n泉水继续在你的体内流动，冲刷那个需要治疗的部位。想象那些不再需要的细胞，就像沙滩上堆积的沙堡，在这股清流的冲刷下，沙粒开始松动、崩塌、随水流走，轻松地、自然地流向身体的出口。你感受到了身体正在变得轻盈、通透。\n\n每一次的呼吸，都在推动着这股净化的循环。你的身体就像是流动的清泉，充满了自我更新的智慧。或许，你能感受到一种前所未有的通透感，那些燥热和不安，都溶解在这清澈的流水中，离开了你的身体，身体里的每一个细胞都在这股清流中欢快地呼吸。你的胃口正在慢慢苏醒，准备接纳那些能转化为能量的食物。\n带着这份通透与清爽，你已经准备好，以最放松、最安稳的状态，去度过这美好的一天。你做得很好，一切都在稳步向好。\n\n\n', 50, '放松、接纳', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000018', '情志区', '内在生长', '大调性长线条pad，激活内在能量，提升积极情绪，叠加Alpha 脑波能让意识保持清醒却不紧绷，助力对引导语的感知，契合 “应对外貌变化、强化内在力量” 的心理目标。', '第三周期（第7-9周）：内在生长 (Inner Growth & Resilience)\n\n\n[声音：沉稳的低音富有力量感，类似民谣或摇篮曲的质感，温暖且私密。森林深处的风声。深邃的森林，低沉的鼓点模拟心跳，树木生长的低频震动。]\nHi你好，欢迎来到这里。这段时间，你的身体经历了很多变化。也许有时你会对自己的身体感到陌生，甚至突如其来的委屈、愤怒或悲伤。这些感受都真实的存在，但请你相信，这些感受都没有错，它们都是你在这场漫长战役里，最诚实的反应。你不必因此而自责，也不必假装“没事”。先停下来，抱抱这个疲惫的自己：“我知道你很难，这些痛、这些怕，我都看见了，也都允许它们存在。”\n\n现在，如果你愿意，我想邀请你，找一个最让你感到舒服的姿势。慢慢闭上眼睛，把注意力轻轻放在身体上，也许你依然能感觉到疼痛，能想起那些难熬的时刻，但别急着推开它们。试着深吸一口气，再慢慢呼出来，将你的觉知深深地扎入你的骨骼之中，那里是你生命的源泉，是你力量的根基。\n想象自己的脊柱，是一颗参天大树的树干，挺拔而正直。无论季节如何更替，大树的生命力始终深藏在它的根部，深藏在它的年轮里。\n\n轻轻抚摸你的手臂，或者你的头部。那些离去的毛发，正如秋天的树叶，为了树叶度过寒冬而落，这不是失去，而是生命深藏的重生的智慧。你的活力没有消失，它只是从外表，深深地收敛进了你的骨骼里。\n\n现在，请跟随我的声音，在你的心里，把下面这些话，唱给自己听：\n（引导语放慢，富有韵律感）\n尽管风暴过境（吸气……）\n我的根系依旧深固（呼气……）\n我并非仅具此身（吸气……）\n我象征勇敢，我闪耀光泽（呼气……）\n我爱当下的我，于破碎中蕴蓄温热。 \n\n仔细感受这些声音的力量，感受这份从骨子里透出来的坚韧。你的根系深深地扎入大地，汲取着源源不断的能量。你很稳，很有力。在你的骨髓深处，有无数健康的种子正在破土而出，那是你的免疫卫士，是你新生的细胞。它们鲜活、强壮，充满了爆发力。你的每一次心跳，都是在为这些新芽输送养分。你的内在，正经历着前所未有的繁荣。\n\n请对着自己微笑，赞赏这个正在努力代谢、生长的身体。你拥有强大的内在核心，这份生命的光彩，比任何外在的修饰都更加耀眼、更加动人。你比你想象的更完整，更美丽。\n你已经准备好，以最放松、最安稳的状态，去度过这美好的一天。你做得很好，一切都在稳步向好。', 45, '积极、力量', '中度激活', true, false, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000019', '情志区', '澄明展望', '弦乐，适配山顶开阔景象，释放身心', '第四周期（第10-12周）：澄明展望 (Clarity & Future)\n\n\n [声音：开阔的山顶，清晨的阳光，逐渐加入的弦乐，带有胜利和希望的色彩]\nHi你好，欢迎来到这里。你已经走过了漫长的旅程，展现了非凡的毅力与智慧。或许，在康复的旅程中，你有时会感到前路有些模糊，不确定感偶尔会浮现，这完全正常。而正是在这样的时刻，你依然选择来到这里，这本身就已经是一份了不起的坚持与智慧。现在，请找一个最舒适的姿势，你将带着你与生俱来的顽强生命力，迎接接下来的每一天。\n\n现在，请闭上双眼，想象你正平静地站在一座高山的顶峰，空气清新纯净。头顶是湛蓝如洗的天空，一束明亮的光芒，穿透云层，照亮了你的前额。在光芒的照耀下，山间的迷雾渐渐散去，视野无比开阔。感受山顶清冽的空气，它流入你的身体。不必刻意思考，只是允许这份开阔感存在。\n然后，当你准备好，可以轻轻地让注意力回到你的身体。沐浴在光芒下，你的身体周围环绕着金色的保护光环，这是你亲手建立的健康防线。身上的伤口正在以惊人的速度愈合，细胞们正在编织新的组织。你的每一个细胞都在欢呼雀跃，它们感受到了这份来自内心深处的滋养与呵护，正以更加饱满的热情投入到修复与重建中。\n\n在这光芒中，或许你会感到思绪也变得清朗一些，仿佛头脑获得了舒展的空间。你的大脑变得更加清晰和敏锐，意志坚定而专注。感受这股清新的能量在你的脑海中盘旋，它唤醒了每一个神经元，让你感到神清气爽。你感受到了内心深处的力量与坚韧，从容与自信。\n\n你站在山顶，仿佛看到了未来那个健康的你，正沐浴在阳光下，做着你最喜欢的事情——也许是散步，也许是旅行，也许只是开心地大笑。看清楚那个画面的色彩，听清楚那里的笑声。那个未来是真实的，它就在不远处等着你。\n\n带着这份清晰的预见和必胜的信念，你已经准备好了，迈向下一个阶段。你比你想象得更强大，更健康。相信自己，你已经赢得了这场新生的战役，美好的未来，它正张开双臂，在前方等你。\n', 56, '积极、自信', '中度激活', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

