INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000001b', '情志区', 'B1', '提升自主神经反应调节能力，皮肤电下降，血压下降', '/', 110, '积极、快乐', '完全激活', false, false, '18岁以上', '精神分裂症患者，物质滥用患者', '["精神分裂症患者","物质滥用患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000001c', '情志区', '心率牵引-01', '1.独特的心率牵引\n采用高质量、高分辨率的沉浸式声音制作技术，塑造独特的心率流线式牵引（在左右、上下的360度空间中，呈现流线型的移动趋势，独具自由叙事功能，变化非常丰富），同时伴随平静状态下的心跳节奏和呼吸频率模拟。\n2.科学的助眠氛围\n音乐渐进放松配合音乐心率训练能够有效促进血液循环，缓解肌肉的紧张程度，提高神经系统的调节功能。同时，所营造的漂浮感可使人的大脑释放出"内啡肽"，还可减轻思想与身体的紧张感。\n3.全景声空间处理\n采用全景声声效，前所未有的空间编码，将声音分布在360度沉浸式空间中，声音在你的周围灵活移动，听者成为全景声听觉的中心，让你全身心的投入睡眠，是一种更具参与性和精确性的体验。\n4.唯美的氛围内容\n专辑的内容共分为三个篇章，分别为宇宙（The Universe）、梦境（The Dream）和漫游（The Wandering）。从不同层面利用心率牵引带领我们来到属于自己、属于世界和属于未来的空间里，在这些空间里不断下坠，探索这片光怪陆离的“幻境”。', '/', 55, '平静', '深度镇静', false, false, '18岁以上', NULL, '["听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000001d', '情志区', 'alpha脑波音乐', 'alpha波8-12Hz，放松而专注，缓解压力，积极的思考，高效学习，自如的参与活动和融入环境', '/', 50, '平静', '深度镇静', false, false, '18岁以上', '严重精神病性障碍患者，严重抑郁患者', '["严重精神病性障碍患者","严重抑郁患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000001e', '情志区', 'theta脑波音乐', 'theta波4-8Hz，REM期睡眠，深度放松/内在平和，冥想，创造力，即将入睡前和觉醒前的状态', '/', 45, '平静', '深度镇静', false, false, '18岁以上', '严重精神病性障碍患者，严重抑郁患者', '["严重精神病性障碍患者","严重抑郁患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-00000000001f', '情志区', '古风《做个神仙》', '知识性\n全面理解待词语言之美和隐藏在音乐中的诗意\n容发性\n通过音乐，领略中国古典诗词韵味，带你重新审视华夏五千年古典文学之美\n趣味性\n古待词中的意境与3D环绕音乐奇妙且完美地融合\n审美性\n高品质独家New Age（新世纪）风格古风音乐欣赏', '/', 85, '积极、快乐', '完全激活', false, false, '18岁以上', '精神分裂症患者，物质滥用患者', '["精神分裂症患者","物质滥用患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000020', '情志区', '动物陪伴冥想《吸猫》', '基于认知行为疗法与动物辅助治疗,以3d音乐音效聆听为基础进行冥想\n\n· 帮助人们唤醒内心最原始的情感,感受内心是如此温柔和友好\n\n· 减缓负性情绪，缓解焦虑，保持宁静与舒适的状态', '现在，找一个让自己觉得舒服的地方坐下。调整自己的呼吸，放松你的身体。\n无论你是否真的拥有一只猫，无论你是否现在正在和猫待在一起，我都邀请你轻柔地感受此刻。\n感受猫趴在腿上，给你的腿部带来的温暖感和重量。\n体会一下，这种温暖的感觉，并尝试把这份温暖慢慢地，扩散到你的全身。\n轻轻地，抚摸它的身体，从它的额头、脖子、躯干、尾巴。再摸摸它柔软的肚子、腿以及它柔软的脚垫。观察它的反应和回应。\n请充分利用你的感官，不要对你观察到的内容做出评判，保持专注，提醒自己去观察、感受、存在。\n你还可以轻柔地，摸摸它的额头和下巴、还有它那个有些凉凉的、湿湿的鼻子。\n现在，你可以看看它那一双大大的眼睛，好看极了，仿佛装满了天地万物，日月星辰。或许可以让你看到蔚蓝的海洋，或许会让你看到浩瀚的宇宙。\n再凑近一点，你可以听到它微弱的呼吸声。\n渐渐地，它发出了咕噜咕噜的声音。\n它很开心，很舒服地躺在你的怀中。\n感受此刻，有这只猫的陪伴，你会发现你越来越放松，呼吸越来越平缓，你能专心于每一个刹那，感受到平和与宁静。\n当你准备好的时候，让我们结束这段体验。慢慢把意识回到当下，活动一下手指和脚趾，你可以稍微伸展一下身体，或许可以尝试把这一篇中所获得的体会记录下来。下一篇中，我们将带你来到森林深处，聆听鸟儿欢快歌唱。我们下次再会。', 50, '放松、平静', '平静放松', true, true, '18岁以上', '创伤后应激障碍', '["创伤后应激障碍","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000021', '情志区', '432hz', '结合「古典摇篮曲+宇宙自然共振标准音+白噪音」，选择经典的古典乐名曲，并进行专业的睡眠向改编，在这里，不论是大人还是孩子都能享受纯净的音乐带来的美好，同时采用宇宙自然共振频率432Hz作为标准音，这是一个柔和、温暖、舒服的频率（目前乐器调音的参考频率一般是440Hz，但一些理论家和音乐家认为432Hz的标准音对人体有更好的效果），并配合白噪音有效的屏蔽外界干扰，感受经典音乐的滋养，帮助身心得到健康的成长，消除负面情绪，平静入眠。\n', '/', 80, '平静', '深度镇静', false, false, '18岁以上', '精神分裂症患者，物质滥用患者', '["精神分裂症患者","物质滥用患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000022', '运动疗愈区', '步态调整', '音乐通过稳定外部节奏，激活听觉 - 运动耦合，代偿受损基底节，修复时间感知，最终让帕金森患者重建流畅、稳定的自主步态', NULL, 80, '积极', '激活', true, false, '50岁以上，帕金森病患者', '癫痫患者，精神分裂症患者，心血管疾病患者，物质滥用患者', '["癫痫患者","精神分裂症患者","心血管疾病患者","物质滥用患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

INSERT INTO therapy_projects (id, region, name, mechanism, guidance_script, bpm, mood, energy_level, has_guidance, has_scenario, target_audience, notes, contraindications)
VALUES ('e0000000-0000-0000-0000-000000000023', '运动疗愈区', '老年认知律动呼吸操', '节奏化的呼吸练习和身体律动，让身体、呼吸和注意力都集中感受音乐的律动中，恰到好处的音乐节拍和动作引导，将带领参与者持续保持一定强度的呼吸频率，带动肢体肌肉的放松，消除疲劳感。', NULL, 80, '积极', '激活', true, false, '60岁以上', '癫痫患者，精神分裂症患者，物质滥用患者', '["癫痫患者","精神分裂症患者","物质滥用患者","听力损失","耳鸣","急性精神病状态","严重心律失常"]'::jsonb);

